// UB budget for one tile: A: blockM*blockK*4, B: blockK*blockN*4, C: blockM*blockN*4
static constexpr uint32_t UB_BUDGET_BYTES = 240 * 1024;  // conservative upper bound per core
static constexpr uint32_t ALIGN_ELEMS = 64;              // DMA alignment

static inline uint32_t AlignDown(uint32_t x, uint32_t a) { return (x / a) * a; }
static inline uint32_t CeilDiv(uint32_t a, uint32_t b) { return (a + b - 1u) / b; }

static ge::graphStatus TilingFunc(gert::TilingContext *context)
{
    using T = MatmulWithTransposedBothCustomTilingData;
    T tiling;

    const auto &shapeA = context->GetInputShape(0)->GetOriginShape();
    const auto &shapeB = context->GetInputShape(1)->GetOriginShape();
    uint32_t K_input = static_cast<uint32_t>(shapeA.GetDim(0));  // A is (K, M)
    uint32_t M       = static_cast<uint32_t>(shapeA.GetDim(1));
    uint32_t N       = static_cast<uint32_t>(shapeB.GetDim(0));  // B is (N, K)

    // Determine tile sizes
    constexpr uint32_t bytesPerElem = 4U;
    // Rough: each tile uses (blockM*blockK + blockK*blockN + blockM*blockN)*4 bytes
    // Solve for block sizes under UB budget
    uint32_t bestBlockM = 128, bestBlockN = 128, bestBlockK = 128;
    uint32_t totalFree = UB_BUDGET_BYTES / bytesPerElem;

    // Heuristic: blockM, blockN, blockK about equal; start from 128
    while (true) {
        uint32_t usage = bestBlockM * bestBlockK + bestBlockK * bestBlockN + bestBlockM * bestBlockN;
        if (usage <= totalFree) break;
        // reduce largest dimension
        if (bestBlockM >= bestBlockN && bestBlockM >= bestBlockK) bestBlockM -= 16;
        else if (bestBlockN >= bestBlockM && bestBlockN >= bestBlockK) bestBlockN -= 16;
        else bestBlockK -= 16;
        bestBlockM = (bestBlockM < 16) ? 16 : bestBlockM;
        bestBlockN = (bestBlockN < 16) ? 16 : bestBlockN;
        bestBlockK = (bestBlockK < 16) ? 16 : bestBlockK;
    }
    bestBlockM = AlignDown(bestBlockM, ALIGN_ELEMS);
    bestBlockN = AlignDown(bestBlockN, ALIGN_ELEMS);
    bestBlockK = AlignDown(bestBlockK, ALIGN_ELEMS);
    if (bestBlockM < ALIGN_ELEMS) bestBlockM = ALIGN_ELEMS;
    if (bestBlockN < ALIGN_ELEMS) bestBlockN = ALIGN_ELEMS;
    if (bestBlockK < ALIGN_ELEMS) bestBlockK = ALIGN_ELEMS;

    uint32_t numBlocksM = CeilDiv(M, bestBlockM);
    uint32_t numBlocksN = CeilDiv(N, bestBlockN);
    uint32_t blockDim = numBlocksM * numBlocksN;
    if (blockDim > 24U) blockDim = 24U;  // cap to available cores

    context->SetBlockDim(blockDim);

    tiling.set_M(M);
    tiling.set_N(N);
    tiling.set_K(K_input);
    tiling.set_blockM(bestBlockM);
    tiling.set_blockN(bestBlockN);
    tiling.set_blockK(bestBlockK);
    tiling.set_numBlocksM(numBlocksM);
    tiling.set_numBlocksN(numBlocksN);
    tiling.set_blockDim(blockDim);

    tiling.SaveToBuffer(context->GetRawTilingData()->GetData(),
                        context->GetRawTilingData()->GetCapacity());
    context->GetRawTilingData()->SetDataSize(tiling.GetDataSize());

    size_t *workspace = context->GetWorkspaceSizes(1);
    workspace[0] = 0;
    return ge::GRAPH_SUCCESS;
}
